package com.shecancode.user.config; import com.shecancode.user.model.AppUser; import com.shecancode.user.repo.UserRepository; import org.springframework.boot.CommandLineRunner; import org.springframework.context.annotation.*; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; @Configuration public class SeedData{@Bean CommandLineRunner seedUsers(UserRepository r,BCryptPasswordEncoder e){return a->{if(r.findByEmailIgnoreCase("admin@shop.local").isEmpty())r.save(new AppUser("Local","Admin","admin@shop.local",e.encode("Admin123!"),"ADMIN"));};}}